# ===== A100 v45.1 Python 3.14 EventLoop Fix =====

# ===== A100 v45.1 Stable Compatibility Patch =====
# v39_candidates 미정의 오류 제거용 공통 후보/스캔 엔진

def a100_candidates(limit=5):
    raw = get_24h_tickers_fast() if "get_24h_tickers_fast" in globals() else []
    rows = []
    stable = {"USDCUSDT", "FDUSDUSDT", "TUSDUSDT", "BUSDUSDT", "USDPUSDT", "DAIUSDT"}
    bad_frag = ["UPUSDT", "DOWNUSDT", "BULLUSDT", "BEARUSDT"]
    for x in raw:
        try:
            sym = x.get("symbol", "")
            if not sym.endswith("USDT") or sym in stable:
                continue
            if any(b in sym for b in bad_frag):
                continue
            qv = float(x.get("quoteVolume", 0))
            pct = float(x.get("priceChangePercent", 0))
            trades = int(x.get("count", 0))
            high = float(x.get("highPrice", 0))
            low = float(x.get("lowPrice", 0))
            last = float(x.get("lastPrice", 0))
            if qv < 3_000_000 or last <= 0:
                continue
            rng = ((high - low) / last * 100) if last else 0
            score = min(qv / 1_000_000, 250) * 0.30
            score += min(trades / 1000, 130) * 0.45
            score += min(abs(pct), 15) * 2.2
            score += min(rng, 20) * 1.4
            if pct > 16: score -= 18
            if pct < -16: score -= 12
            rows.append((score, sym, pct, qv, trades))
        except Exception:
            continue
    rows.sort(reverse=True)
    if rows:
        return rows[:limit]
    return [(0, s, 0, 0, 0) for s in top_usdt(limit)]

def a100_scan_one(sym):
    try:
        if "analyze" in globals():
            return analyze(sym)
    except TypeError:
        pass
    try:
        res = scan([sym])
        return res[0] if res else None
    except Exception as e:
        log(f"a100_scan_one error {sym}: {e}")
        return None

def a100_parallel_scan(symbols):
    results = []
    if not symbols:
        return results
    workers = int(os.getenv("PARALLEL_WORKERS", "5"))
    with ThreadPoolExecutor(max_workers=min(workers, len(symbols))) as ex:
        futures = {ex.submit(a100_scan_one, s): s for s in symbols}
        for fut in as_completed(futures):
            sym = futures[fut]
            try:
                r = fut.result(timeout=12)
                if r:
                    results.append(r)
            except Exception as e:
                log(f"a100_parallel_scan error {sym}: {e}")
    return results

def v41_score(r):
    try:
        s = (
            timing_score(r) * 0.28 +
            breakout_score(r) * 0.24 +
            bottom_score(r) * 0.20 +
            real_signal_score(r) * 0.15 +
            win_rate_estimate(r) * 0.09 -
            chase_risk(r) * 0.10
        )
        vol = min(max(float(getattr(r, "vol_ratio", 1)), 0), 4)
        s += vol * 4
        if chase_risk(r) >= 70:
            s = min(s, 55)
        mode = v41_market_mode() if "v41_market_mode" in globals() else "중립"
        if "RISK OFF" in mode and not r.sym.startswith(("BTC", "ETH")):
            s -= 5
        return round(max(0, min(100, s)), 1)
    except Exception:
        return round(getattr(r, "score", 0), 1)

