            r = BINANCE_SESSION.get(url, timeout=V43_TIMEOUT)
            if r.status_code == 200:
                data = r.json()
                if isinstance(data, list) and len(data) > 50:
                    return data, host, None
            last_err = f"{host} status {getattr(r, 'status_code', '?')} {str(getattr(r, 'text', ''))[:80]}"
