async def ultimate_cmd(update, context):
    t0 = now_ts()
    await update.message.reply_text("🧬 A100 v45.1 Binance 캐시 기반 분석 중...")
    try:
        rows = v43_candidates(V43_LIMIT)
        if not rows:
            err = TICKER_CACHE.get("err", "") if "TICKER_CACHE" in globals() else ""
            await update.message.reply_text(
                "⚠️ Binance ticker 캐시가 비어 있습니다.\n"
                "서버 네트워크/API 차단 가능성이 있습니다.\n"
                f"오류: {err[:180]}"
            )
            return

        syms = [r[1] for r in rows[:V43_ANALYZE_LIMIT]]
        res = a100_parallel_scan(syms) if "a100_parallel_scan" in globals() else scan(syms)
        res = sorted(res, key=lambda r: v43_score(r), reverse=True)
        res = [r for r in res if v43_score(r) >= V43_MIN_SCORE][:V43_TOP]
        elapsed = round(now_ts() - t0, 1)

        lines = [
            "🧬 <b>A100 v45.1 BINANCE CACHE FIX</b>",
            f"시장상태: <b>{v41_market_mode()}</b>",
            f"1차후보 {len(rows)}개 → 정밀 {len(syms)}개 → TOP{len(res)} | 소요 {elapsed}초",
            "Binance host failover / User-Agent / keep-alive 적용",
            "────────────",
            ""
        ]
        if not res:
            lines.append("현재 기준 통과 후보 없음. 무리한 진입보다 대기.")
        for i, r in enumerate(res, 1):
            lines.append(v43_format(r, i))
            lines.append("────────────")
            try:
                v41_record_pick(r, i)
            except Exception as e:
                log(f"record error {e}")

        await update.message.reply_text("\n".join(lines), parse_mode="HTML", disable_web_page_preview=True)
    except Exception as e:
        log(f"v43 ultimate error: {e}\n{traceback.format_exc()}")
        await update.message.reply_text(f"ultimate 오류: {e}")

