async def cgtest_cmd(update, context):
    coin = (context.args[0].upper() if context.args else "BTC").replace("USDT", "")
    sup = v45_cg_supported(force=True)
    raw = v45_cg_coin(coin, force=True)
    m = v52_normalize_cg(raw)
