        f"성공: {stats['wins']}회\n"
        f"TP2: {stats['tp2']}회\n"
        f"TP1 후 보호종료: {stats['partial']}회\n"
        f"손절: {stats['losses']}회\n"
        f"누적 승률: <b>{stats['win_rate']}%</b>\n"
