V90_COMMAND_REGISTRY["legacycheck"] = legacycheck90_1_cmd
V90_EXPECTED_COMMANDS = frozenset(V90_COMMAND_REGISTRY)

def build_v44_application(token):
    """
    명령 누락을 막기 위해 CommandHandler 104개를 따로 등록하지 않는다.
    모든 /명령은 단 하나의 MessageHandler가 레지스트리를 통해 처리한다.
    """
    audit = v90_registry_audit()
    invalid = audit["missing_callbacks"] + audit["non_callable"]
    if invalid:
        raise RuntimeError(
            "V90.1 registry validation failed: " + ",".join(invalid)
        )

    app = Application.builder().token(token).build()

    # 단 하나의 명령 처리 경로
    app.add_handler(
        MessageHandler(filters.COMMAND, v90_1_dispatch),
        group=0,
    )
    app.add_error_handler(v88_error_handler)

    print(f"A100 V90.2 registered commands: {len(V90_COMMAND_REGISTRY)}", flush=True)
    print("A100 V90.2 dispatcher count: 1", flush=True)
    print("A100 V90.2 registry validation: OK", flush=True)
    return app

async def run_bot_async():
    """
    기존 버전은 재연결 때마다 drop_pending_updates=True를 사용해
    재시작 또는 네트워크 복구 구간에 들어온 명령이 사라질 수 있었다.
    V90.1은 대기 명령을 보존한다.
    """
    global V59_ALERT_TASK

    token = os.getenv("TELEGRAM_BOT_TOKEN") or os.getenv("BOT_TOKEN")
    if not token:
        raise RuntimeError("TELEGRAM_BOT_TOKEN is missing")

    retry_delay = V44_RETRY_MIN
    first_start = True

    while True:
        app = None
        try:
            app = build_v44_application(token)

            await app.initialize()

            # webhook만 해제하고 사용자의 대기 명령은 삭제하지 않는다.
            await app.bot.delete_webhook(drop_pending_updates=False)
            print("A100 V90.2: webhook deleted, pending updates preserved", flush=True)

            await app.start()
            await app.updater.start_polling(
                drop_pending_updates=False,
                allowed_updates=Update.ALL_TYPES,
                poll_interval=0.5,
                timeout=20,
                bootstrap_retries=3,
            )

            if V59_AUTO_ALERT and CHAT_ID:
                V59_ALERT_TASK = asyncio.create_task(v59_auto_alert_loop(app))
                print("A100 V90.2: auto alert loop started", flush=True)

            if V925_LEARNING_ALERT_ENABLED and CHAT_ID:
                V925_LEARNING_ALERT_TASK = asyncio.create_task(v925_learning_alert_loop(app))
                print(f"A100 V92.5: learning report loop started ({V925_LEARNING_ALERT_HOURS:g}h)", flush=True)

            print("A100 V90.2: Telegram single polling started", flush=True)
            retry_delay = V44_RETRY_MIN
            first_start = False

            while app.updater.running:
                await asyncio.sleep(5)

            raise RuntimeError("Telegram updater stopped unexpectedly")

        except Conflict as error:
            print(
                f"A100 V90.2 Conflict: another getUpdates instance is active. "
                f"Retrying in {retry_delay}s: {error}",
                flush=True,
            )
        except (NetworkError, TimedOut) as error:
            print(
                f"A100 V90.2 Telegram network error. "
                f"Retry in {retry_delay}s: {error}",
                flush=True,
            )
        except asyncio.CancelledError:
            if V59_ALERT_TASK:
                V59_ALERT_TASK.cancel()
                V59_ALERT_TASK = None
            await stop_v44_application(app)
            raise
        except Exception as error:
            v88_record_error("v90.1-polling-loop", error)
            print(
                f"A100 V90.2 polling error. Retry in {retry_delay}s: "
                f"{type(error).__name__}: {error}",
                flush=True,
            )

        if V59_ALERT_TASK:
            V59_ALERT_TASK.cancel()
            V59_ALERT_TASK = None
        if V925_LEARNING_ALERT_TASK:
            V925_LEARNING_ALERT_TASK.cancel()
            V925_LEARNING_ALERT_TASK = None
        await stop_v44_application(app)
        await asyncio.sleep(retry_delay)
        retry_delay = min(retry_delay * 2, V44_RETRY_MAX)

def main():
    start_health_server_once()
    print("A100 V90.2 BOOT & COMMAND RELIABILITY ENGINE worker running...", flush=True)

    if not acquire_v44_process_lock():
        print("A100 V90.2 duplicate polling process blocked", flush=True)
        while True:
            time.sleep(60)

    try:
        asyncio.run(run_bot_async())
    except KeyboardInterrupt:
        print("A100 V90.2 stopped by signal", flush=True)
    except Exception as error:
        v88_record_error("v90.1-fatal-main", error)
        print(traceback.format_exc(), flush=True)
        raise



# ===== A100 V90.3 STABILITY & SHARED CONTEXT REFACTOR =====
# V90.2의 모든 기존 명령을 유지하면서 심볼 상태, 공통 분석 캐시,
# 상태 점검 및 재연결 안정성을 강화한다.
V90_3_VERSION = "A100 V90.3 STABILITY & SHARED CONTEXT"
V90_3_STARTED_AT = time.time()
V90_3_ANALYSIS_TTL = int(os.getenv("V90_3_ANALYSIS_TTL", "60"))
V90_3_SYMBOL_REFRESH = int(os.getenv("V90_3_SYMBOL_REFRESH", "86400"))
V90_3_ANALYSIS_CACHE = {}
V90_3_ANALYSIS_LOCK = threading.RLock()
V90_3_CACHE_HITS = 0
V90_3_CACHE_MISSES = 0
V90_3_SYMBOL_REFRESH_AT = 0.0
V90_3_SYMBOL_REFRESH_ERROR = ""

# 최종 analyze 구현을 보존한 뒤 동일 심볼의 중복 계산을 짧게 재사용한다.
_v90_3_analyze_base = analyze

def _v90_3_kr_fingerprint(kr):
    try:
        return int(KR_CACHE[0] // 60)
    except Exception:
        return 0

def analyze(sym, kr):
    global V90_3_CACHE_HITS, V90_3_CACHE_MISSES
    pair = normalize_usdt_symbol(sym)
    key = (pair, _v90_3_kr_fingerprint(kr))
    now = time.time()
    with V90_3_ANALYSIS_LOCK:
        item = V90_3_ANALYSIS_CACHE.get(key)
        if item and now - item[0] <= V90_3_ANALYSIS_TTL:
            V90_3_CACHE_HITS += 1
            return item[1]
    result = _v90_3_analyze_base(pair, kr)
    with V90_3_ANALYSIS_LOCK:
        V90_3_ANALYSIS_CACHE[key] = (now, result)
        V90_3_CACHE_MISSES += 1
        if len(V90_3_ANALYSIS_CACHE) > 500:
            cutoff = now - max(V90_3_ANALYSIS_TTL * 3, 180)
            stale = [k for k, v in V90_3_ANALYSIS_CACHE.items() if v[0] < cutoff]
            for k in stale:
                V90_3_ANALYSIS_CACHE.pop(k, None)
    return result

def v90_3_refresh_symbols(force=False):
    global V90_3_SYMBOL_REFRESH_AT, V90_3_SYMBOL_REFRESH_ERROR
    try:
        symbols = binance_spot_symbols(force=force)
        if symbols:
            # 구버전 진단 코드가 참조하는 이름도 동기화한다.
            globals()["V78_VALID_SYMBOLS"] = set(symbols)
            V90_3_SYMBOL_REFRESH_AT = time.time()
            V90_3_SYMBOL_REFRESH_ERROR = ""
            return True
        V90_3_SYMBOL_REFRESH_ERROR = "empty symbol list"
    except Exception as error:
        V90_3_SYMBOL_REFRESH_ERROR = f"{type(error).__name__}: {error}"[:300]
        log(f"V90.3 symbol refresh failed: {V90_3_SYMBOL_REFRESH_ERROR}")
    return bool(_BINANCE_SYMBOL_CACHE.get("symbols"))

def v90_3_symbol_refresh_loop():
    # 첫 시작 직후 1회, 이후 하루 1회 갱신. 실패 시 기존 캐시는 유지한다.
    while True:
        v90_3_refresh_symbols(force=True)
        time.sleep(max(3600, V90_3_SYMBOL_REFRESH))

def v90_3_start_background_once():
    if globals().get("_V90_3_BACKGROUND_STARTED"):
        return
    globals()["_V90_3_BACKGROUND_STARTED"] = True
    threading.Thread(target=v90_3_symbol_refresh_loop, daemon=True, name="v90.3-symbol-refresh").start()

def v90_3_symbol_ready():
    symbols = globals().get("V78_VALID_SYMBOLS") or _BINANCE_SYMBOL_CACHE.get("symbols")
    if symbols:
        return True
    return v90_3_refresh_symbols(force=False)

def v90_3_registry_status():
    audit = v90_registry_audit()
    return audit, not audit["missing_callbacks"] and not audit["non_callable"]

