V90_COMMAND_REGISTRY["health"] = health90_4_cmd
V90_COMMAND_REGISTRY["selfcheck"] = selfcheck90_4_cmd
V90_COMMAND_REGISTRY["legacycheck"] = legacycheck90_4_cmd
