V917_SIMILARITY_MIN_SAMPLES = _v91_int("PAPER_SIMILARITY_MIN_SAMPLES", 8, 3, 5000)
V917_SIMILARITY_TOP_K = _v91_int("PAPER_SIMILARITY_TOP_K", 30, 5, 500)
