async def outcomememory1150_core(update,context):
    rows=_v1150_outcome_memory(_v91_load_state())
    lines=[f"📚 <b>{_v1150_banner('OUTCOME MEMORY ENGINE')}</b>",f"결과 메모리 그룹 <b>{len(rows)}개</b> · 최근 90일",""]
