    if missing_help:
        lines.append("Help 누락: " + ", ".join("/" + x for x in missing_help[:30]))
    if failed:
        lines.append("실패 항목: " + ", ".join(failed))
    return await v90_1_safe_reply(update, "\n".join(lines), parse_mode="HTML")


