    lines += ["", "<b>Targets</b>"]
    lines += ["✅ 모든 운영 성능 목표 충족"] if not reasons else ["⚠️ " + _v54_escape(x) for x in reasons]
    lines.append("Cache ≥80% · Processing P95 ≤10s · Duplicate Reads 0")
    return await v90_1_safe_reply(update, "\n".join(lines), parse_mode="HTML")


