async def releasegate1160rc4924_cmd(update, context):
    _, cert, hit, lm = _v1160_rc4924_gate_snapshot()
    mode, _ = _v1160_rc495_mode(cert)
    prog, passed, total = _v1160_rc496_progress(cert)
    gate = cert.get("gate", {}) or {}
