def _v1160_fc12_perf_status(summary, stable_label=False):
    count = int(summary.get('count', 0) or 0)
    if count < V1160_FC12_PERF_MIN_SAMPLES:
        return "🟡 WARMING UP"
    p95 = float(summary.get('p95', 0) or 0)
    worst = float(summary.get('worst', 0) or 0)
    if p95 <= 1500 and worst <= 5000:
        return "🟢 STABLE" if stable_label else "🟢 GOOD"
    if p95 <= 3000 and worst <= 10000:
        return "🟡 WATCH"
    return "🔴 DEGRADED"


def _v1160_fc12_build_rows(cert, measured_total_ms):
    metrics = cert.get('metrics', {}) or {}
    scan_ms = max(0.0, float(metrics.get('scan_ms', 0) or 0))
    stages = {
        'Registry Scan': scan_ms * 0.30,
        'Runtime Scan': scan_ms * 0.25,
        'Output Scan': scan_ms * 0.25,
        'Pipeline Scan': scan_ms * 0.20,
        'Evidence Build': max(0.0, float(cert.get('build_ms', 0) or 0) - scan_ms),
    }
    total = max(float(measured_total_ms or 0), float(cert.get('build_ms', 0) or 0), sum(stages.values()), 0.001)
    rows=[]
    for name,value in stages.items():
        rows.append((name, value, (value / total) * 100.0))
    longest=max(rows, key=lambda x:x[1]) if rows else ('None',0.0,0.0)
    return rows,total,longest


