def _v1160_s21714_rows_window(hours):
    now = time.time(); selected = []
    for r in _v1160_s21712_rows():
        try:
            raw = r.get("epoch")
            ts = float(raw) if raw is not None else datetime.fromisoformat(str(r.get("ts") or r.get("utc")).replace("Z", "+00:00")).timestamp()
            if 0.0 <= now - ts <= float(hours) * 3600.0:
                rr = dict(r); rr["_epoch"] = ts; selected.append(rr)
        except Exception:
            pass
    selected.sort(key=lambda x: x.get("_epoch", 0.0))
    return selected


def _v1160_s21714_avg(rows, key):
    vals=[]
    for r in rows:
        try:
            v=r.get(key)
            if v is not None: vals.append(float(v))
        except Exception: pass
    return (sum(vals)/len(vals)) if vals else None


def _v1160_s21714_calibrated_score(snap):
    """Conservative evidence calibration; never changes mandatory gate authority."""
    base=float(((snap or {}).get("runtime") or {}).get("score",0.0) or 0.0)
    rows=_v1160_s21714_rows_window(72)
    if not rows: return round(base,1), {"samples":0,"coverage":0.0,"history":None,"adjustment":0.0}
    scores=[float(r.get("runtime_score",base)) for r in rows if r.get("runtime_score") is not None]
    hist=(sum(scores)/len(scores)) if scores else base
    coverage=min(1.0,len(rows)/4320.0)  # 60-second samples over 72h
    errors=sum(max(0,int(r.get("runtime_errors",0) or 0)) for r in rows)
    error_factor=1.0 if errors==0 else max(0.0,1.0-errors/max(1,len(rows)))
    mem=[float(r.get("memory_mb")) for r in rows if r.get("memory_mb") is not None]
    mem_factor=1.0
    if len(mem)>1 and sum(mem)/len(mem)>0:
        mean=sum(mem)/len(mem); variance=sum((x-mean)**2 for x in mem)/len(mem)
        mem_factor=max(0.0,min(1.0,1.0-(variance**0.5)/mean))
    cache=_v1160_s21714_avg(rows,"operational_hit_rate")
    cache_factor=max(0.0,min(1.0,(cache or 0.0)/100.0))
    quality=100.0*(0.40*coverage+0.25*error_factor+0.20*mem_factor+0.15*cache_factor)
    evidence_target=0.65*hist+0.35*quality
    weight=min(0.35,0.05+0.30*coverage)
    adjusted=base*(1.0-weight)+evidence_target*weight
    adjusted=max(base-3.0,min(base+5.0,adjusted))
    return round(adjusted,1), {"samples":len(rows),"coverage":coverage*100.0,"history":hist,"quality":quality,"adjustment":adjusted-base}


