def _v1160_s21714_runtime_history_lines():
    out=["RUNTIME WINDOW ENGINE V2"]
    expected={"1h":60,"6h":360,"24h":1440,"72h":4320}
    for label,hours in (("1h",1),("6h",6),("24h",24),("72h",72)):
        rows=_v1160_s21714_rows_window(hours)
        score=_v1160_s21714_avg(rows,"runtime_score"); mem=_v1160_s21714_avg(rows,"memory_mb"); cache=_v1160_s21714_avg(rows,"operational_hit_rate")
        errs=sum(int(r.get("runtime_errors",0) or 0) for r in rows)
        delta=0.0
        if len(rows)>1:
            try: delta=float(rows[-1].get("runtime_score",0))-float(rows[0].get("runtime_score",0))
            except Exception: pass
        coverage=min(100.0,len(rows)/expected[label]*100.0)
        if score is None: out.append(f"{label:<4} samples   0/{expected[label]} · coverage 0.0% · PENDING"); continue
        out.append(f"{label:<4} samples {len(rows):>4}/{expected[label]} · coverage {coverage:.1f}%")
        out.append(f"     runtime {score:.1f} · delta {delta:+.1f} · memory {mem:.1f}MB" if mem is not None else f"     runtime {score:.1f} · delta {delta:+.1f} · memory PENDING")
        out[-1]+=f" · cache {cache:.1f}%" if cache is not None else " · cache PENDING"
        out[-1]+=f" · errors {errs}"
        if rows:
            first=datetime.fromtimestamp(rows[0]["_epoch"],timezone.utc).strftime('%m-%d %H:%M')
            last=datetime.fromtimestamp(rows[-1]["_epoch"],timezone.utc).strftime('%m-%d %H:%M')
            out.append(f"     window UTC {first} → {last}")
    return out


def _v1160_s2173_gate_detail(label,current,target,velocity):
    gap=max(0.0,float(target)-float(current))
    if gap<=0:return ["Status detail          CERTIFIED",f"Margin                 {abs(float(target)-float(current)):.1f}"]
    factors={
        "Intelligence":("Prediction calibration","Validated sample breadth","Regime consistency"),
        "Strategy Trust":("Closed-outcome sample depth","Entry/exit consistency","Regime-stable trust"),
        "Outcome Quality":("Attribution completeness","Exit precision","Fee/slippage-positive expectancy"),
        "Memory Health":("Leak-free observation time","Snapshot stability","Worker/cache bounded growth"),
        "LTS Readiness":("Mandatory gate completion","72H runtime evidence","Performance/evidence validation"),
    }.get(label,("Mandatory evidence","Runtime validation","Certification stability"))
    raw_h=gap/max(float(velocity or 0.0),0.01)
    with V1160_S21714_ETA_LOCK:
        old=float(V1160_S21714_ETA_STATE.get(label,raw_h) or raw_h)
        # EMA plus a 25% movement cap per observation prevents request-to-request oscillation.
        ema=old*0.75+raw_h*0.25; cap=max(12.0,old*0.25); stable=max(old-cap,min(old+cap,ema))
        V1160_S21714_ETA_STATE[label]=stable
        _v1160_s21714_atomic_json(V1160_S21714_ETA_FILE,V1160_S21714_ETA_STATE)
    return [f"Primary gap            {factors[0]}",f"Secondary gaps         {factors[1]} · {factors[2]}",f"Velocity ETA           {stable/24.0:.1f}d (EMA stabilized)"]


