def _v1160_s21734_bar(current, target=100.0, width=12):
    """Consistent display-only gauge. Never reads files or rebuilds evidence."""
    current=float(current or 0.0); target=float(target or 0.0)
    pct=100.0 if target <= 0 else max(0.0,min(100.0,current/target*100.0))
    filled=max(0,min(width,int(round(pct*width/100.0))))
    return "█"*filled + "░"*(width-filled), pct


def _v1160_s21734_production_ready(st):
    """Conservative presentation score derived only from worker-cached values.

    This is not an authoritative Release Gate and does not change any threshold,
    gate formula, evidence rule, or certification decision.
    """
    runtime=max(0.0,min(100.0,float(st.get('runtime_score',0.0) or 0.0)))
    gates=max(0.0,min(100.0,float(st.get('gate_passed',0) or 0)*20.0))
    coverage=max(0.0,min(100.0,float(st.get('coverage_72h',0.0) or 0.0)))
    score=min(runtime,gates,coverage)
    if score >= 100.0 and st.get('worker_fresh') and st.get('evidence_ready'):
        state='READY'
    elif score >= 80.0:
        state='FINALIZING'
    else:
        state='MEASURING'
    return score,state


def _v1160_s21734_overview_lines(st):
    runtime_bar,runtime_pct=_v1160_s21734_bar(st.get('runtime_score',0.0),100.0)
    gates_bar,gates_pct=_v1160_s21734_bar(st.get('gate_passed',0),5.0)
    coverage=float(st.get('coverage_72h',0.0) or 0.0)
    cert_bar,cert_pct=_v1160_s21734_bar(coverage,100.0)
    ready,ready_state=_v1160_s21734_production_ready(st)
    ready_bar,_=_v1160_s21734_bar(ready,100.0)
    return [
        "📊 LIVE OPERATIONS",
        f"⚙️ Runtime       {runtime_bar} {runtime_pct:5.1f}%",
        f"🚦 Release Gate  {gates_bar} {gates_pct:5.1f}% · {int(st.get('gate_passed',0))}/5",
        f"⏱️ 72H Evidence  {cert_bar} {cert_pct:5.1f}%",
        f"🚀 Production    {ready_bar} {ready:5.1f}% · {ready_state}",
    ]


def _v1160_s21734_gate_lines(st):
    rows=[]
    for idx,row in enumerate(st.get('gate_matrix') or (),1):
        current=float(row.get('current',0.0) or 0.0)
        target=float(row.get('target',0.0) or 0.0)
        gap=max(0.0,float(row.get('gap',0.0) or 0.0))
        bar,pct=_v1160_s21734_bar(current,target)
        passed=bool(row.get('passed'))
        marker='✅' if passed else '⏳'
        trend=_v1160_s21733_delta_text(row.get('delta',0.0)).replace('Trend ','Δ ')
        rows.extend([
            f"{marker} {idx}. {row.get('label','-')} · {'PASS' if passed else 'BLOCKED'}",
            f"   {bar} {pct:5.1f}% · {current:.1f}/{target:.1f}",
            f"   Remaining {'0.0' if passed else f'+{gap:.1f}'} · {trend}",
        ])
    return rows or ['⏳ Gate evidence warming · worker publish pending']


def _v1160_s21734_certification_lines(st):
    coverage=max(0.0,min(100.0,float(st.get('coverage_72h',0.0) or 0.0)))
    hours=coverage*72.0/100.0
    bar,pct=_v1160_s21734_bar(coverage,100.0)
    state='✅ CERTIFIED' if coverage >= 100.0 else '⏱️ MEASURING'
    return [
        "⏱️ 72H RUNTIME CERTIFICATION",
        f"{bar} {pct:5.1f}% · {hours:.1f}/72.0H",
        f"Status {state} · persisted evidence only",
    ]


